//! Slint-free domain contract for the F4SE diagnostics tab.
//!
//! The reference Tkinter tab lives in `CMT/src/tabs/_f4se.py`. This module keeps
//! the same user-facing labels, icon strings, and row compatibility rules in
//! pure Rust so scanner workers and Slint UI code can depend on a stable typed
//! contract without re-reading Python source or touching filesystem/process/UI
//! APIs.

use crate::domain::discovery::{
    DATA_FOLDER_NOT_FOUND_MESSAGE, F4SE_PLUGINS_NOT_FOUND_MESSAGE, Fallout4InstallType,
};

/// Reference tab title used by the original notebook tab.
pub const F4SE_TAB_TITLE: &str = "F4SE";
/// Reference loading text shown while DLL scanning runs.
pub const F4SE_LOADING_TEXT: &str = "Scanning DLLs...";
/// Reference table columns in display order.
pub const F4SE_TABLE_COLUMNS: [&str; 5] = ["DLL", "OG", "NG", "AE", "Your Game"];
/// Reference heading shown next to the DLL table.
pub const F4SE_HEADING: &str = "F4SE DLLs";
/// Reference loading error used when the Fallout 4 `Data` folder is unavailable.
pub const F4SE_DATA_FOLDER_NOT_FOUND_MESSAGE: &str = DATA_FOLDER_NOT_FOUND_MESSAGE;
/// Reference loading error prefix used when `Data/F4SE/Plugins` is unavailable.
pub const F4SE_PLUGINS_FOLDER_NOT_FOUND_MESSAGE: &str = F4SE_PLUGINS_NOT_FOUND_MESSAGE;
/// Reference hint appended when the app was not launched through a mod manager.
pub const F4SE_MOD_MANAGER_HINT: &str = "Try launching via your mod manager.";
/// Reference information/legend text from `ABOUT_F4SE_DLLS`.
pub const F4SE_LEGEND_TEXT: &str = "This checks all DLLs in\nData/F4SE/Plugins/ for\nversion-specific code to\ndetermine OG/NG support.\n\n✔ Version is supported\n\n❌ Version not supported\n\n❓ Not an F4SE DLL.\nMay still be loaded by\nother DLLs.\n\n⚠ Consult mod page to\nverify version support if\nyou see this icon.\nSome DLLs' version support\ncannot be reliably\ndetermined.";

const DETAIL_NOT_F4SE: &str = "Not an F4SE DLL. May still be loaded by other DLLs.";
const DETAIL_AMBIGUOUS_NGAE: &str = "Some DLLs' version support cannot be reliably determined. Consult the mod page to verify version support.";
const DETAIL_UNKNOWN_GAME: &str = "Your current Fallout 4 version could not be classified; compatibility with Your Game is unknown.";
const DETAIL_INCOMPATIBLE: &str = "Version not supported for the current game.";
const DETAIL_COMPATIBLE: &str = "Version is supported for the current game.";

/// Returns the reference `Data/F4SE/Plugins` missing-folder message.
///
/// The Python tab appends the mod-manager hint only when no mod manager was
/// detected, because launching through a manager is how the virtual plugin folder
/// normally becomes visible.
pub fn f4se_missing_plugins_message(mod_manager_detected: bool) -> String {
    if mod_manager_detected {
        F4SE_PLUGINS_FOLDER_NOT_FOUND_MESSAGE.to_owned()
    } else {
        format!("{F4SE_PLUGINS_FOLDER_NOT_FOUND_MESSAGE}\n{F4SE_MOD_MANAGER_HINT}")
    }
}

/// Current game generation used to classify the `Your Game` F4SE column.
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, Hash)]
pub enum F4seGameTarget {
    /// Fallout 4 1.10.163-era runtime, including the reference `Down-Grade` state.
    OldGen,
    /// Fallout 4 Next-Gen runtime.
    NextGen,
    /// Fallout 4 Anniversary runtime.
    Anniversary,
    /// The current runtime could not be mapped to OG, NG, or AE.
    #[default]
    Unknown,
}

impl F4seGameTarget {
    /// Maps the broader discovery install type into the F4SE target generations.
    ///
    /// `NextGenAnniversary` is intentionally mapped to [`F4seGameTarget::Unknown`]
    /// because the F4SE table needs one concrete current runtime for the `Your
    /// Game` column; treating a combined binary classification as either NG or AE
    /// would hide uncertainty.
    pub const fn from_install_type(install_type: Fallout4InstallType) -> Self {
        match install_type {
            Fallout4InstallType::OldGen | Fallout4InstallType::DownGrade => Self::OldGen,
            Fallout4InstallType::NextGen => Self::NextGen,
            Fallout4InstallType::Anniversary => Self::Anniversary,
            Fallout4InstallType::Obsolete
            | Fallout4InstallType::NextGenAnniversary
            | Fallout4InstallType::Unknown
            | Fallout4InstallType::NotFound => Self::Unknown,
        }
    }
}

/// Compatibility icon semantics for a rendered F4SE table cell.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum F4seCompatibilityIcon {
    /// Empty cell used by the reference OG/NG/AE columns for unsupported versions.
    UnsupportedReferenceColumn,
    /// Explicit blank cell used for non-F4SE rows in the `Your Game` column.
    Blank,
    /// Reference black question mark ornament for non-F4SE or unknown DLL facts.
    Unknown,
    /// Reference heavy check mark for supported versions.
    Supported,
    /// Reference cross mark for confirmed current-game incompatibility.
    UnsupportedCurrentGame,
    /// Reference warning sign for ambiguous support or unknown current-game state.
    Warning,
}

impl F4seCompatibilityIcon {
    /// Returns the exact icon string used by the reference Tkinter tab.
    pub const fn as_reference_str(self) -> &'static str {
        match self {
            Self::UnsupportedReferenceColumn | Self::Blank => "",
            Self::Unknown => "❓",
            Self::Supported => "✔",
            Self::UnsupportedCurrentGame => "❌",
            Self::Warning => "⚠",
        }
    }
}

/// Semantic state behind a rendered F4SE compatibility cell.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum F4seCompatibilityState {
    /// The relevant version is supported.
    Supported,
    /// The relevant reference column is known unsupported but intentionally blank.
    UnsupportedReferenceColumn,
    /// The current game is known unsupported and should show a cross mark.
    UnsupportedCurrentGame,
    /// The DLL is not known to be F4SE or could not be inspected.
    Unknown,
    /// The support state is ambiguous or the current game target is unknown.
    Warning,
    /// Intentionally empty non-applicable cell.
    Blank,
}

/// Rendered F4SE compatibility cell independent of Slint table models.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct F4seCompatibilityCell {
    /// Reference icon category for this cell.
    pub icon: F4seCompatibilityIcon,
    /// Semantic state represented by the icon.
    pub state: F4seCompatibilityState,
    /// Safe user-facing detail suitable for row-detail panes or tooltips.
    pub detail: &'static str,
}

impl F4seCompatibilityCell {
    fn supported(detail: &'static str) -> Self {
        Self {
            icon: F4seCompatibilityIcon::Supported,
            state: F4seCompatibilityState::Supported,
            detail,
        }
    }

    fn unsupported_reference(detail: &'static str) -> Self {
        Self {
            icon: F4seCompatibilityIcon::UnsupportedReferenceColumn,
            state: F4seCompatibilityState::UnsupportedReferenceColumn,
            detail,
        }
    }

    fn unsupported_current_game() -> Self {
        Self {
            icon: F4seCompatibilityIcon::UnsupportedCurrentGame,
            state: F4seCompatibilityState::UnsupportedCurrentGame,
            detail: DETAIL_INCOMPATIBLE,
        }
    }

    fn unknown(detail: &'static str) -> Self {
        Self {
            icon: F4seCompatibilityIcon::Unknown,
            state: F4seCompatibilityState::Unknown,
            detail,
        }
    }

    fn warning(detail: &'static str) -> Self {
        Self {
            icon: F4seCompatibilityIcon::Warning,
            state: F4seCompatibilityState::Warning,
            detail,
        }
    }

    fn blank(detail: &'static str) -> Self {
        Self {
            icon: F4seCompatibilityIcon::Blank,
            state: F4seCompatibilityState::Blank,
            detail,
        }
    }
}

/// Reference row tag names used for F4SE table coloring.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum F4seRowTag {
    /// Reference `neutral` tag for non-F4SE rows.
    Neutral,
    /// Reference `good` tag for current-game compatible F4SE rows.
    Good,
    /// Reference `bad` tag for confirmed current-game incompatible F4SE rows.
    Bad,
    /// Reference `note` tag for ambiguous or warning rows.
    Note,
}

impl F4seRowTag {
    /// Returns the exact Tkinter tag name used by the reference tab.
    pub const fn as_reference_str(self) -> &'static str {
        match self {
            Self::Neutral => "neutral",
            Self::Good => "good",
            Self::Bad => "bad",
            Self::Note => "note",
        }
    }
}

/// Severity bucket for UI filtering, detail panels, and future tracing summaries.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum F4seRowSeverity {
    /// Non-F4SE or otherwise informational row.
    Neutral,
    /// Current game is compatible.
    Compatible,
    /// Current game is confirmed incompatible.
    Incompatible,
    /// Compatibility could not be determined confidently.
    Warning,
}

/// Raw DLL facts produced by a future F4SE scanner before UI rendering.
///
/// These fields mirror the reference `DLLInfo` keys while allowing inspection
/// failures to stay visible. `exports_version` corresponds to the Python
/// `SupportsNGAE` flag (`F4SEPlugin_Version` exists). `supports_ng` and
/// `supports_ae` are `None` when the version export exists but compatible
/// versions could not be recognized reliably.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct F4seDllFacts {
    /// Basename displayed in the `DLL` column.
    pub dll_name: String,
    /// Whether the scanner confirmed F4SE exports; `None` means inspection failed.
    pub is_f4se: Option<bool>,
    /// Whether `F4SEPlugin_Query` was found, matching OG support in the reference.
    pub exports_query: bool,
    /// Whether `F4SEPlugin_Version` was found, matching NGAE support in the reference.
    pub exports_version: bool,
    /// NG support inferred from `compatibleVersions`, or ambiguous if `None`.
    pub supports_ng: Option<bool>,
    /// AE support inferred from `compatibleVersions`, or ambiguous if `None`.
    pub supports_ae: Option<bool>,
    /// Safe inspection failure message; raw parse details should stay in logs.
    pub inspection_error: Option<String>,
}

impl F4seDllFacts {
    /// Creates facts for a confirmed non-F4SE DLL.
    pub fn non_f4se(dll_name: impl Into<String>) -> Self {
        Self {
            dll_name: dll_name.into(),
            is_f4se: Some(false),
            exports_query: false,
            exports_version: false,
            supports_ng: None,
            supports_ae: None,
            inspection_error: None,
        }
    }

    /// Creates facts for a confirmed F4SE DLL.
    ///
    /// `supports_ng` and `supports_ae` should be populated only from parsed
    /// `F4SEPlugin_Version.compatibleVersions` facts. Passing `None` while
    /// `exports_version` is true preserves the reference warning-icon behavior.
    pub fn f4se(
        dll_name: impl Into<String>,
        exports_query: bool,
        exports_version: bool,
        supports_ng: Option<bool>,
        supports_ae: Option<bool>,
    ) -> Self {
        Self {
            dll_name: dll_name.into(),
            is_f4se: Some(true),
            exports_query,
            exports_version,
            supports_ng,
            supports_ae,
            inspection_error: None,
        }
    }

    /// Creates facts for a DLL that could not be inspected safely.
    ///
    /// The message is intended for user-visible diagnostics and should not expose
    /// raw unread bytes or platform-specific exception text.
    pub fn inspection_failed(dll_name: impl Into<String>, safe_message: impl Into<String>) -> Self {
        Self {
            dll_name: dll_name.into(),
            is_f4se: None,
            exports_query: false,
            exports_version: false,
            supports_ng: None,
            supports_ae: None,
            inspection_error: Some(safe_message.into()),
        }
    }
}

/// Rendered F4SE row ready for conversion into UI table models.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct F4seDllRow {
    /// Basename displayed in the `DLL` column.
    pub dll_name: String,
    /// Rendered OG support cell.
    pub og: F4seCompatibilityCell,
    /// Rendered NG support cell.
    pub ng: F4seCompatibilityCell,
    /// Rendered AE support cell.
    pub ae: F4seCompatibilityCell,
    /// Rendered current-game support cell.
    pub your_game: F4seCompatibilityCell,
    /// Reference row tag for color mapping.
    pub tag: F4seRowTag,
    /// Higher-level severity derived from the current-game cell.
    pub severity: F4seRowSeverity,
    /// Safe row detail messages for diagnostics panes or accessibility labels.
    pub details: Vec<String>,
}

/// Overall F4SE scan state used by controllers and UI status text.
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, Hash)]
pub enum F4seScanStatus {
    /// No F4SE scan has started yet.
    #[default]
    Idle,
    /// A worker is currently scanning DLLs.
    Loading,
    /// Scan completed and row data is available.
    Ready,
    /// Scan could not start or complete enough to show rows.
    Error,
}

/// Snapshot of the F4SE tab state independent of Slint models.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct F4seScanSnapshot {
    /// Current scan status.
    pub status: F4seScanStatus,
    /// User-visible status or loading/error message.
    pub status_message: String,
    /// Rendered DLL rows, preserving the scanner-provided order.
    pub rows: Vec<F4seDllRow>,
}

impl F4seScanSnapshot {
    /// Creates an idle empty snapshot.
    pub fn idle() -> Self {
        Self {
            status: F4seScanStatus::Idle,
            status_message: String::new(),
            rows: Vec::new(),
        }
    }

    /// Creates the reference loading snapshot.
    pub fn loading() -> Self {
        Self {
            status: F4seScanStatus::Loading,
            status_message: F4SE_LOADING_TEXT.to_owned(),
            rows: Vec::new(),
        }
    }

    /// Creates a ready snapshot with rendered rows.
    pub fn ready(rows: Vec<F4seDllRow>) -> Self {
        Self {
            status: F4seScanStatus::Ready,
            status_message: String::new(),
            rows,
        }
    }

    /// Creates the reference Data-folder missing snapshot.
    pub fn missing_data_folder() -> Self {
        Self::error(F4SE_DATA_FOLDER_NOT_FOUND_MESSAGE)
    }

    /// Creates the reference F4SE plugins-folder missing snapshot.
    pub fn missing_plugins_folder(mod_manager_detected: bool) -> Self {
        Self::error(f4se_missing_plugins_message(mod_manager_detected))
    }

    /// Creates an error snapshot from a safe user-facing message.
    pub fn error(message: impl Into<String>) -> Self {
        Self {
            status: F4seScanStatus::Error,
            status_message: message.into(),
            rows: Vec::new(),
        }
    }
}

/// Renders scanner facts into F4SE table rows for a specific current-game target.
pub fn render_f4se_dll_rows(
    facts: &[F4seDllFacts],
    current_game: F4seGameTarget,
) -> Vec<F4seDllRow> {
    facts
        .iter()
        .map(|fact| render_f4se_dll_row(fact, current_game))
        .collect()
}

/// Renders a single DLL fact record using the reference F4SE table rules.
pub fn render_f4se_dll_row(facts: &F4seDllFacts, current_game: F4seGameTarget) -> F4seDllRow {
    if facts.inspection_error.is_some() || facts.is_f4se.is_none() {
        return render_inspection_failed_row(facts);
    }

    if facts.is_f4se == Some(false) {
        return render_non_f4se_row(facts);
    }

    let og = if facts.exports_query {
        F4seCompatibilityCell::supported("OG support comes from F4SEPlugin_Query.")
    } else {
        F4seCompatibilityCell::unsupported_reference("F4SEPlugin_Query was not found.")
    };
    let ng = render_ngae_reference_cell(facts.exports_version, facts.supports_ng, "NG");
    let ae = render_ngae_reference_cell(facts.exports_version, facts.supports_ae, "AE");
    let your_game = render_current_game_cell(facts, current_game);
    let (tag, severity) = row_style_from_current_cell(&your_game);

    let mut details = Vec::new();
    if your_game.icon == F4seCompatibilityIcon::Warning
        || ng.icon == F4seCompatibilityIcon::Warning
        || ae.icon == F4seCompatibilityIcon::Warning
    {
        details.push(DETAIL_AMBIGUOUS_NGAE.to_owned());
    }
    if current_game == F4seGameTarget::Unknown {
        details.push(DETAIL_UNKNOWN_GAME.to_owned());
    }
    match your_game.state {
        F4seCompatibilityState::Supported => details.push(DETAIL_COMPATIBLE.to_owned()),
        F4seCompatibilityState::UnsupportedCurrentGame => {
            details.push(DETAIL_INCOMPATIBLE.to_owned())
        }
        F4seCompatibilityState::UnsupportedReferenceColumn
        | F4seCompatibilityState::Unknown
        | F4seCompatibilityState::Warning
        | F4seCompatibilityState::Blank => {}
    }

    F4seDllRow {
        dll_name: facts.dll_name.clone(),
        og,
        ng,
        ae,
        your_game,
        tag,
        severity,
        details,
    }
}

fn render_non_f4se_row(facts: &F4seDllFacts) -> F4seDllRow {
    F4seDllRow {
        dll_name: facts.dll_name.clone(),
        og: F4seCompatibilityCell::unknown(DETAIL_NOT_F4SE),
        ng: F4seCompatibilityCell::unknown(DETAIL_NOT_F4SE),
        ae: F4seCompatibilityCell::unknown(DETAIL_NOT_F4SE),
        your_game: F4seCompatibilityCell::blank(DETAIL_NOT_F4SE),
        tag: F4seRowTag::Neutral,
        severity: F4seRowSeverity::Neutral,
        details: vec![DETAIL_NOT_F4SE.to_owned()],
    }
}

fn render_inspection_failed_row(facts: &F4seDllFacts) -> F4seDllRow {
    let detail = facts
        .inspection_error
        .clone()
        .unwrap_or_else(|| "Could not inspect DLL. Compatibility is unknown.".to_owned());
    F4seDllRow {
        dll_name: facts.dll_name.clone(),
        og: F4seCompatibilityCell::unknown("DLL inspection failed."),
        ng: F4seCompatibilityCell::unknown("DLL inspection failed."),
        ae: F4seCompatibilityCell::unknown("DLL inspection failed."),
        your_game: F4seCompatibilityCell::warning("DLL inspection failed."),
        tag: F4seRowTag::Note,
        severity: F4seRowSeverity::Warning,
        details: vec![detail],
    }
}

fn render_ngae_reference_cell(
    exports_version: bool,
    supports_runtime: Option<bool>,
    runtime_name: &'static str,
) -> F4seCompatibilityCell {
    if !exports_version {
        return F4seCompatibilityCell::unsupported_reference("F4SEPlugin_Version was not found.");
    }

    match supports_runtime {
        Some(true) => F4seCompatibilityCell::supported(match runtime_name {
            "NG" => "NG support was found in compatibleVersions.",
            "AE" => "AE support was found in compatibleVersions.",
            _ => "Support was found in compatibleVersions.",
        }),
        Some(false) => F4seCompatibilityCell::unsupported_reference(match runtime_name {
            "NG" => "NG support was not found in compatibleVersions.",
            "AE" => "AE support was not found in compatibleVersions.",
            _ => "Support was not found in compatibleVersions.",
        }),
        None => F4seCompatibilityCell::warning(DETAIL_AMBIGUOUS_NGAE),
    }
}

fn render_current_game_cell(
    facts: &F4seDllFacts,
    current_game: F4seGameTarget,
) -> F4seCompatibilityCell {
    match current_game {
        F4seGameTarget::OldGen => {
            if facts.exports_query {
                F4seCompatibilityCell::supported(DETAIL_COMPATIBLE)
            } else {
                F4seCompatibilityCell::unsupported_current_game()
            }
        }
        F4seGameTarget::NextGen => render_current_ngae_cell(facts, facts.supports_ng),
        F4seGameTarget::Anniversary => render_current_ngae_cell(facts, facts.supports_ae),
        F4seGameTarget::Unknown => F4seCompatibilityCell::warning(DETAIL_UNKNOWN_GAME),
    }
}

fn render_current_ngae_cell(
    facts: &F4seDllFacts,
    supports_runtime: Option<bool>,
) -> F4seCompatibilityCell {
    if !facts.exports_version {
        return F4seCompatibilityCell::unsupported_current_game();
    }

    match supports_runtime {
        Some(true) => F4seCompatibilityCell::supported(DETAIL_COMPATIBLE),
        Some(false) => F4seCompatibilityCell::unsupported_current_game(),
        None => F4seCompatibilityCell::warning(DETAIL_AMBIGUOUS_NGAE),
    }
}

fn row_style_from_current_cell(cell: &F4seCompatibilityCell) -> (F4seRowTag, F4seRowSeverity) {
    match cell.state {
        F4seCompatibilityState::Supported => (F4seRowTag::Good, F4seRowSeverity::Compatible),
        F4seCompatibilityState::UnsupportedCurrentGame => {
            (F4seRowTag::Bad, F4seRowSeverity::Incompatible)
        }
        F4seCompatibilityState::Warning => (F4seRowTag::Note, F4seRowSeverity::Warning),
        F4seCompatibilityState::UnsupportedReferenceColumn
        | F4seCompatibilityState::Unknown
        | F4seCompatibilityState::Blank => (F4seRowTag::Neutral, F4seRowSeverity::Neutral),
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::domain::discovery::Fallout4InstallType;

    #[test]
    fn f4se_domain_reference_strings_are_locked() {
        assert_eq!(F4SE_TAB_TITLE, "F4SE");
        assert_eq!(F4SE_LOADING_TEXT, "Scanning DLLs...");
        assert_eq!(F4SE_TABLE_COLUMNS, ["DLL", "OG", "NG", "AE", "Your Game"]);
        assert_eq!(F4SE_HEADING, "F4SE DLLs");
        assert_eq!(F4SE_DATA_FOLDER_NOT_FOUND_MESSAGE, "Data folder not found");
        assert_eq!(
            F4SE_PLUGINS_FOLDER_NOT_FOUND_MESSAGE,
            "Data/F4SE/Plugins folder not found"
        );
        assert_eq!(F4SE_MOD_MANAGER_HINT, "Try launching via your mod manager.");
        assert_eq!(
            f4se_missing_plugins_message(true),
            "Data/F4SE/Plugins folder not found"
        );
        assert_eq!(
            f4se_missing_plugins_message(false),
            "Data/F4SE/Plugins folder not found\nTry launching via your mod manager."
        );
        assert_eq!(
            F4SE_LEGEND_TEXT,
            "This checks all DLLs in\nData/F4SE/Plugins/ for\nversion-specific code to\ndetermine OG/NG support.\n\n✔ Version is supported\n\n❌ Version not supported\n\n❓ Not an F4SE DLL.\nMay still be loaded by\nother DLLs.\n\n⚠ Consult mod page to\nverify version support if\nyou see this icon.\nSome DLLs' version support\ncannot be reliably\ndetermined."
        );
    }

    #[test]
    fn f4se_domain_icon_mapping_matches_reference() {
        assert_eq!(F4seCompatibilityIcon::Unknown.as_reference_str(), "❓");
        assert_eq!(F4seCompatibilityIcon::Supported.as_reference_str(), "✔");
        assert_eq!(
            F4seCompatibilityIcon::UnsupportedReferenceColumn.as_reference_str(),
            ""
        );
        assert_eq!(
            F4seCompatibilityIcon::UnsupportedCurrentGame.as_reference_str(),
            "❌"
        );
        assert_eq!(F4seCompatibilityIcon::Warning.as_reference_str(), "⚠");
        assert_eq!(F4seRowTag::Neutral.as_reference_str(), "neutral");
        assert_eq!(F4seRowTag::Good.as_reference_str(), "good");
        assert_eq!(F4seRowTag::Bad.as_reference_str(), "bad");
        assert_eq!(F4seRowTag::Note.as_reference_str(), "note");
    }

    #[test]
    fn f4se_domain_non_f4se_rendering_matches_reference() {
        let facts = F4seDllFacts::non_f4se("helper.dll");
        let row = render_f4se_dll_row(&facts, F4seGameTarget::NextGen);

        assert_eq!(row.dll_name, "helper.dll");
        assert_eq!(row.og.icon, F4seCompatibilityIcon::Unknown);
        assert_eq!(row.ng.icon, F4seCompatibilityIcon::Unknown);
        assert_eq!(row.ae.icon, F4seCompatibilityIcon::Unknown);
        assert_eq!(row.your_game.icon, F4seCompatibilityIcon::Blank);
        assert_eq!(row.tag, F4seRowTag::Neutral);
        assert_eq!(row.severity, F4seRowSeverity::Neutral);
        assert!(
            row.details
                .iter()
                .any(|detail| detail.contains("Not an F4SE DLL"))
        );
    }

    #[test]
    fn f4se_domain_f4se_without_version_export_is_confirmed_unsupported_for_ngae() {
        let facts = F4seDllFacts::f4se("legacy.dll", true, false, None, None);
        let row = render_f4se_dll_row(&facts, F4seGameTarget::NextGen);

        assert_eq!(row.og.icon, F4seCompatibilityIcon::Supported);
        assert_eq!(
            row.ng.icon,
            F4seCompatibilityIcon::UnsupportedReferenceColumn
        );
        assert_eq!(
            row.ae.icon,
            F4seCompatibilityIcon::UnsupportedReferenceColumn
        );
        assert_eq!(
            row.your_game.icon,
            F4seCompatibilityIcon::UnsupportedCurrentGame
        );
        assert_eq!(row.tag, F4seRowTag::Bad);
        assert_eq!(row.severity, F4seRowSeverity::Incompatible);
    }

    #[test]
    fn f4se_domain_ambiguous_ngae_rendering_uses_warning_icons() {
        let facts = F4seDllFacts::f4se("ambiguous.dll", true, true, None, None);
        let row = render_f4se_dll_row(&facts, F4seGameTarget::Anniversary);

        assert_eq!(row.og.icon, F4seCompatibilityIcon::Supported);
        assert_eq!(row.ng.icon, F4seCompatibilityIcon::Warning);
        assert_eq!(row.ae.icon, F4seCompatibilityIcon::Warning);
        assert_eq!(row.your_game.icon, F4seCompatibilityIcon::Warning);
        assert_eq!(row.tag, F4seRowTag::Note);
        assert_eq!(row.severity, F4seRowSeverity::Warning);
        assert!(
            row.details
                .iter()
                .any(|detail| detail.contains("cannot be reliably determined"))
        );
    }

    #[test]
    fn f4se_domain_current_game_mapping_is_target_specific() {
        let facts = F4seDllFacts::f4se("modern.dll", true, true, Some(true), Some(false));

        assert_eq!(
            render_f4se_dll_row(&facts, F4seGameTarget::OldGen)
                .your_game
                .icon,
            F4seCompatibilityIcon::Supported
        );
        assert_eq!(
            render_f4se_dll_row(&facts, F4seGameTarget::NextGen)
                .your_game
                .icon,
            F4seCompatibilityIcon::Supported
        );
        assert_eq!(
            render_f4se_dll_row(&facts, F4seGameTarget::Anniversary)
                .your_game
                .icon,
            F4seCompatibilityIcon::UnsupportedCurrentGame
        );
        assert_eq!(
            F4seGameTarget::from_install_type(Fallout4InstallType::DownGrade),
            F4seGameTarget::OldGen
        );
        assert_eq!(
            F4seGameTarget::from_install_type(Fallout4InstallType::NextGen),
            F4seGameTarget::NextGen
        );
        assert_eq!(
            F4seGameTarget::from_install_type(Fallout4InstallType::Anniversary),
            F4seGameTarget::Anniversary
        );
        assert_eq!(
            F4seGameTarget::from_install_type(Fallout4InstallType::NextGenAnniversary),
            F4seGameTarget::Unknown
        );
    }

    #[test]
    fn f4se_domain_unknown_game_target_warns_without_hiding_facts() {
        let facts = F4seDllFacts::f4se("known.dll", false, true, Some(true), Some(true));
        let row = render_f4se_dll_row(&facts, F4seGameTarget::Unknown);

        assert_eq!(
            row.og.icon,
            F4seCompatibilityIcon::UnsupportedReferenceColumn
        );
        assert_eq!(row.ng.icon, F4seCompatibilityIcon::Supported);
        assert_eq!(row.ae.icon, F4seCompatibilityIcon::Supported);
        assert_eq!(row.your_game.icon, F4seCompatibilityIcon::Warning);
        assert_eq!(row.tag, F4seRowTag::Note);
        assert_ne!(row.severity, F4seRowSeverity::Incompatible);
        assert!(
            row.details
                .iter()
                .any(|detail| detail.contains("could not be classified"))
        );
    }

    #[test]
    fn f4se_domain_scan_snapshot_models_loading_and_safe_errors() {
        assert_eq!(F4seScanSnapshot::loading().status, F4seScanStatus::Loading);
        assert_eq!(
            F4seScanSnapshot::loading().status_message,
            F4SE_LOADING_TEXT
        );

        let missing_data = F4seScanSnapshot::missing_data_folder();
        assert_eq!(missing_data.status, F4seScanStatus::Error);
        assert_eq!(
            missing_data.status_message,
            F4SE_DATA_FOLDER_NOT_FOUND_MESSAGE
        );

        let missing_plugins = F4seScanSnapshot::missing_plugins_folder(false);
        assert_eq!(missing_plugins.status, F4seScanStatus::Error);
        assert_eq!(
            missing_plugins.status_message,
            "Data/F4SE/Plugins folder not found\nTry launching via your mod manager."
        );
    }

    #[test]
    fn f4se_domain_inspection_failures_render_safe_unknown_cells() {
        let facts = F4seDllFacts::inspection_failed(
            "broken.dll",
            "Could not inspect DLL. Check file permissions or whether the file is malformed.",
        );
        let row = render_f4se_dll_row(&facts, F4seGameTarget::Anniversary);

        assert_eq!(row.og.icon, F4seCompatibilityIcon::Unknown);
        assert_eq!(row.ng.icon, F4seCompatibilityIcon::Unknown);
        assert_eq!(row.ae.icon, F4seCompatibilityIcon::Unknown);
        assert_eq!(row.your_game.icon, F4seCompatibilityIcon::Warning);
        assert_eq!(row.tag, F4seRowTag::Note);
        assert!(
            row.details
                .iter()
                .any(|detail| detail.contains("Could not inspect DLL"))
        );
    }
}

//! Pure domain contracts for Fallout 4 discovery state.
//!
//! These types deliberately do not touch the filesystem, registry, processes, or
//! Slint. Later platform adapters can populate them from real discovery work
//! while tests can construct them from inline paths and values.

use std::{
    collections::BTreeMap,
    fmt,
    path::{Path, PathBuf},
};

/// Reference game identifier used by the original Python `GameInfo` object.
pub const FALLOUT4_GAME_ID: &str = "Fallout4";
/// Executable name used to recognize a Fallout 4 installation directory.
pub const FALLOUT4_EXECUTABLE: &str = "Fallout4.exe";
/// Reference-compatible message shown when no valid game path is available.
pub const FALLOUT4_NOT_FOUND_MESSAGE: &str = "A Fallout 4 installation could not be found.";
/// Reference-compatible loading error used by Overview, F4SE, and Scanner paths.
pub const DATA_FOLDER_NOT_FOUND_MESSAGE: &str = "Data folder not found";
/// Reference-compatible F4SE loading error prefix.
pub const F4SE_PLUGINS_NOT_FOUND_MESSAGE: &str = "Data/F4SE/Plugins folder not found";

/// Semantic version used for tools and discovered executables.
///
/// The reference app uses Python's `packaging.version.Version` for manager
/// versions. The current Rust domain contract only needs a stable three-part
/// semantic version plus a `0.0.0` fallback for unknown executable metadata.
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct SemanticVersion {
    /// Major version component.
    pub major: u64,
    /// Minor version component.
    pub minor: u64,
    /// Patch version component.
    pub patch: u64,
}

impl SemanticVersion {
    /// Creates a semantic version from major, minor, and patch components.
    pub const fn new(major: u64, minor: u64, patch: u64) -> Self {
        Self {
            major,
            minor,
            patch,
        }
    }

    /// Returns the reference-compatible fallback used when file metadata is unavailable.
    pub const fn zero() -> Self {
        Self::new(0, 0, 0)
    }
}

impl fmt::Display for SemanticVersion {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(formatter, "{}.{}.{}", self.major, self.minor, self.patch)
    }
}

/// Reference install-type labels from `CMT/src/enums.py`.
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, Hash)]
pub enum Fallout4InstallType {
    /// Reference `Obsolete` state.
    Obsolete,
    /// Reference `Old-Gen` state.
    OldGen,
    /// Reference `Down-Grade` state.
    DownGrade,
    /// Reference `Next-Gen` state.
    NextGen,
    /// Reference `Anniversary` state.
    Anniversary,
    /// Reference `Next-Gen & Anniversary` state.
    NextGenAnniversary,
    /// Reference default state before binary classification runs.
    #[default]
    Unknown,
    /// Reference state used when a base executable is absent.
    NotFound,
}

impl Fallout4InstallType {
    /// Returns the exact user-facing label used by the reference enum.
    pub const fn as_reference_str(self) -> &'static str {
        match self {
            Self::Obsolete => "Obsolete",
            Self::OldGen => "Old-Gen",
            Self::DownGrade => "Down-Grade",
            Self::NextGen => "Next-Gen",
            Self::Anniversary => "Anniversary",
            Self::NextGenAnniversary => "Next-Gen & Anniversary",
            Self::Unknown => "Unknown",
            Self::NotFound => "Not Found",
        }
    }
}

impl fmt::Display for Fallout4InstallType {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.as_reference_str())
    }
}

/// Pure representation of a discovered Fallout 4 installation.
///
/// `game_path` is the only required path. `data_path` and `f4se_plugins_path`
/// remain optional because the reference app can have a valid game executable
/// while Data or Data/F4SE/Plugins are absent, producing recoverable tab-level
/// loading messages instead of invalidating the installation itself.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Fallout4Installation {
    /// Directory containing `Fallout4.exe`.
    pub game_path: PathBuf,
    /// Optional `Data` directory if a platform adapter has confirmed one.
    pub data_path: Option<PathBuf>,
    /// Optional `Data/F4SE/Plugins` directory if confirmed.
    pub f4se_plugins_path: Option<PathBuf>,
    /// Binary classification state for the current install.
    pub install_type: Fallout4InstallType,
    /// Archive records observed by later scanner/overview workflows.
    pub archives: Vec<ArchiveRecord>,
    /// Plugin/module records observed by later scanner/overview workflows.
    pub modules: Vec<ModuleRecord>,
    /// Parsed Fallout 4 INI state from the user profile.
    pub ini_files: Fallout4IniFiles,
}

impl Fallout4Installation {
    /// Creates an installation with only the required game path.
    ///
    /// This constructor performs no existence checks and intentionally does not
    /// infer `Data` or `F4SE` paths, preserving the Phase 3 contract that those
    /// derived paths are optional facts supplied by discovery adapters.
    pub fn new(game_path: impl Into<PathBuf>) -> Self {
        Self {
            game_path: game_path.into(),
            data_path: None,
            f4se_plugins_path: None,
            install_type: Fallout4InstallType::Unknown,
            archives: Vec::new(),
            modules: Vec::new(),
            ini_files: Fallout4IniFiles::default(),
        }
    }

    /// Creates an installation with optional derived paths supplied by an adapter.
    pub fn with_optional_paths(
        game_path: impl Into<PathBuf>,
        data_path: Option<impl Into<PathBuf>>,
        f4se_plugins_path: Option<impl Into<PathBuf>>,
    ) -> Self {
        let mut installation = Self::new(game_path);
        installation.data_path = data_path.map(Into::into);
        installation.f4se_plugins_path = f4se_plugins_path.map(Into::into);
        installation
    }

    /// Returns the reference game identifier for this installation contract.
    pub const fn game_id(&self) -> &'static str {
        FALLOUT4_GAME_ID
    }

    /// Returns whether an adapter has confirmed a Data directory.
    pub const fn has_data_path(&self) -> bool {
        self.data_path.is_some()
    }

    /// Returns whether an adapter has confirmed a Data/F4SE/Plugins directory.
    pub const fn has_f4se_plugins_path(&self) -> bool {
        self.f4se_plugins_path.is_some()
    }
}

/// Archive file format magic recognized by the reference scanner.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum ArchiveFormat {
    /// General BA2 archive (`GNRL`).
    General,
    /// DirectX 10 texture BA2 archive (`DX10`).
    DirectX10,
    /// Any other archive format marker retained for diagnostics.
    Unknown(String),
}

impl ArchiveFormat {
    /// Returns the reference byte marker text when the format is known.
    pub const fn as_reference_magic(&self) -> Option<&'static str> {
        match self {
            Self::General => Some("GNRL"),
            Self::DirectX10 => Some("DX10"),
            Self::Unknown(_) => None,
        }
    }
}

/// BA2 version classes used by the archive overview and patcher workflows.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum ArchiveVersion {
    /// v1, required by Old-Gen Fallout 4 and accepted by all versions.
    OldGen,
    /// v7, initial Next-Gen archive version.
    NextGen7,
    /// v8, current Next-Gen archive version.
    NextGen8,
    /// Any other version byte retained for diagnostics.
    Unknown(u32),
}

impl ArchiveVersion {
    /// Converts the typed archive version into the numeric value in the BA2 header.
    pub const fn as_header_value(self) -> u32 {
        match self {
            Self::OldGen => 1,
            Self::NextGen7 => 7,
            Self::NextGen8 => 8,
            Self::Unknown(value) => value,
        }
    }
}

/// Single archive record carried by scanner and overview workflows.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ArchiveRecord {
    /// Archive path as discovered by a platform/scanner adapter.
    pub path: PathBuf,
    /// Parsed archive format marker.
    pub format: ArchiveFormat,
    /// Parsed archive version.
    pub version: ArchiveVersion,
    /// Whether later enablement parsing found this archive active.
    pub enabled: bool,
    /// Whether the scanner could read enough bytes to classify the archive.
    pub readable: bool,
}

impl ArchiveRecord {
    /// Creates a readable archive record with an explicit enabled state.
    pub fn new(
        path: impl Into<PathBuf>,
        format: ArchiveFormat,
        version: ArchiveVersion,
        enabled: bool,
    ) -> Self {
        Self {
            path: path.into(),
            format,
            version,
            enabled,
            readable: true,
        }
    }

    /// Creates an unreadable archive record while preserving its path.
    pub fn unreadable(path: impl Into<PathBuf>) -> Self {
        Self {
            path: path.into(),
            format: ArchiveFormat::Unknown(String::new()),
            version: ArchiveVersion::Unknown(0),
            enabled: false,
            readable: false,
        }
    }
}

/// Module/header classes used for ESP/ESM/ESL overview state.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum ModuleHeaderVersion {
    /// Reference-supported HEDR v0.95.
    Version095,
    /// Reference-supported HEDR v1.00.
    Version100,
    /// Any unsupported header value retained as text for diagnostics.
    Unknown(String),
}

impl ModuleHeaderVersion {
    /// Returns the reference display text for known module header versions.
    pub const fn as_reference_str(&self) -> Option<&'static str> {
        match self {
            Self::Version095 => Some("0.95"),
            Self::Version100 => Some("1.00"),
            Self::Unknown(_) => None,
        }
    }
}

/// Plugin/module kind inferred from flags and extension.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum ModuleKind {
    /// Full plugin/module.
    Full,
    /// Light plugin/module, matching the reference light flag grouping.
    Light,
}

/// Single plugin/module record carried by scanner and overview workflows.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ModuleRecord {
    /// Module path as discovered by a platform/scanner adapter.
    pub path: PathBuf,
    /// Full or light module classification.
    pub kind: ModuleKind,
    /// Parsed HEDR/header version.
    pub header_version: ModuleHeaderVersion,
    /// Whether plugin enablement parsing found this module active.
    pub enabled: bool,
    /// Whether the scanner could read enough bytes to classify the module.
    pub readable: bool,
}

impl ModuleRecord {
    /// Creates a readable module record with explicit enablement state.
    pub fn new(
        path: impl Into<PathBuf>,
        kind: ModuleKind,
        header_version: ModuleHeaderVersion,
        enabled: bool,
    ) -> Self {
        Self {
            path: path.into(),
            kind,
            header_version,
            enabled,
            readable: true,
        }
    }

    /// Creates an unreadable module record while preserving its path.
    pub fn unreadable(path: impl Into<PathBuf>) -> Self {
        Self {
            path: path.into(),
            kind: ModuleKind::Full,
            header_version: ModuleHeaderVersion::Unknown(String::new()),
            enabled: false,
            readable: false,
        }
    }
}

/// Parsed key/value contents for a single Fallout 4 INI file.
#[derive(Debug, Default, Clone, PartialEq, Eq)]
pub struct IniDocument {
    /// Optional source path used for diagnostics and later reload operations.
    pub source_path: Option<PathBuf>,
    /// Lowercase section names mapped to lowercase setting keys and raw values.
    pub sections: BTreeMap<String, BTreeMap<String, String>>,
}

impl IniDocument {
    /// Creates an empty INI document with an optional source path.
    pub fn new(source_path: Option<impl Into<PathBuf>>) -> Self {
        Self {
            source_path: source_path.map(Into::into),
            sections: BTreeMap::new(),
        }
    }

    /// Returns a setting value by already-normalized section and key names.
    pub fn get(&self, section: &str, key: &str) -> Option<&str> {
        self.sections
            .get(section)
            .and_then(|settings| settings.get(key))
            .map(String::as_str)
    }
}

/// Parsed Fallout 4 INI documents used by overview/scanner behavior.
#[derive(Debug, Default, Clone, PartialEq, Eq)]
pub struct Fallout4IniFiles {
    /// Parsed `Fallout4.ini` settings.
    pub fallout4: IniDocument,
    /// Parsed `Fallout4Prefs.ini` settings.
    pub prefs: IniDocument,
    /// Parsed `Fallout4Custom.ini` settings.
    pub custom: IniDocument,
}

/// Recoverable discovery failure with a safe user-facing message.
///
/// Raw OS details should be kept in `diagnostic` unless a reference message
/// intentionally includes a path, such as the invalid registry path and missing
/// environment-folder cases.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DiscoveryError {
    /// Typed failure category.
    pub kind: DiscoveryErrorKind,
    /// Non-user-facing detail for logs or diagnostics.
    pub diagnostic: Option<String>,
}

impl DiscoveryError {
    /// Creates the generic reference-compatible Fallout 4 not-found error.
    pub fn fallout4_not_found(diagnostic: impl Into<Option<String>>) -> Self {
        Self {
            kind: DiscoveryErrorKind::Fallout4NotFound,
            diagnostic: diagnostic.into(),
        }
    }

    /// Creates the invalid-registry-path error whose reference text includes the path.
    pub fn invalid_registry_path(path: impl Into<PathBuf>) -> Self {
        Self {
            kind: DiscoveryErrorKind::InvalidRegistryPath { path: path.into() },
            diagnostic: None,
        }
    }

    /// Creates the environment-folder missing error whose reference text includes the path.
    pub fn environment_folder_missing(path: impl Into<PathBuf>) -> Self {
        Self {
            kind: DiscoveryErrorKind::EnvironmentFolderMissing { path: path.into() },
            diagnostic: None,
        }
    }

    /// Creates the reference-compatible Data folder loading error.
    pub fn data_folder_not_found() -> Self {
        Self {
            kind: DiscoveryErrorKind::DataFolderNotFound,
            diagnostic: None,
        }
    }

    /// Creates the reference-compatible F4SE plugins loading error.
    pub fn f4se_plugins_folder_not_found(mod_manager_detected: bool) -> Self {
        Self {
            kind: DiscoveryErrorKind::F4sePluginsFolderNotFound {
                mod_manager_detected,
            },
            diagnostic: None,
        }
    }

    /// Returns the message safe to show to users.
    pub fn user_message(&self) -> String {
        match &self.kind {
            DiscoveryErrorKind::Fallout4NotFound => FALLOUT4_NOT_FOUND_MESSAGE.to_owned(),
            DiscoveryErrorKind::InvalidRegistryPath { path } => format!(
                "A Fallout 4 installation could not be found.\n\nThe path set in your registry is:\n{}\n\nIf this is not correct, please run the Fallout 4 Launcher to correct it.",
                display_path(path)
            ),
            DiscoveryErrorKind::EnvironmentFolderMissing { path } => {
                format!("Folder does not exist:\n{}", display_path(path))
            }
            DiscoveryErrorKind::DataFolderNotFound => DATA_FOLDER_NOT_FOUND_MESSAGE.to_owned(),
            DiscoveryErrorKind::F4sePluginsFolderNotFound {
                mod_manager_detected,
            } => {
                if *mod_manager_detected {
                    F4SE_PLUGINS_NOT_FOUND_MESSAGE.to_owned()
                } else {
                    format!("{F4SE_PLUGINS_NOT_FOUND_MESSAGE}\nTry launching via your mod manager.")
                }
            }
        }
    }

    /// Returns whether the failure should be handled without terminating discovery orchestration.
    pub const fn is_recoverable(&self) -> bool {
        true
    }

    /// Returns whether resolving this error requires a manual file-picker UI.
    ///
    /// Phase 3 adapters should report the error and let higher layers decide how
    /// to recover; the domain contract itself does not mandate the reference
    /// Tkinter file-picker prompt.
    pub const fn requires_manual_file_picker(&self) -> bool {
        false
    }
}

impl fmt::Display for DiscoveryError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(&self.user_message())
    }
}

impl std::error::Error for DiscoveryError {}

/// Typed discovery failure categories.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum DiscoveryErrorKind {
    /// No valid Fallout 4 installation path could be found.
    Fallout4NotFound,
    /// A registry value was present but did not identify a valid Fallout 4 directory.
    InvalidRegistryPath {
        /// Registry path text intentionally included by the reference user message.
        path: PathBuf,
    },
    /// A required Windows known folder did not exist.
    EnvironmentFolderMissing {
        /// Missing folder path intentionally included by the reference helper.
        path: PathBuf,
    },
    /// A tab/workflow required Data but discovery did not provide it.
    DataFolderNotFound,
    /// A tab/workflow required Data/F4SE/Plugins but discovery did not provide it.
    F4sePluginsFolderNotFound {
        /// Whether a mod manager was already detected, matching the reference hint behavior.
        mod_manager_detected: bool,
    },
}

fn display_path(path: &Path) -> String {
    path.display().to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn fallout4_installation_does_not_require_data_or_f4se_paths() {
        let installation = Fallout4Installation::new("C:/Games/Fallout 4");

        assert_eq!(installation.game_id(), "Fallout4");
        assert_eq!(installation.game_path, PathBuf::from("C:/Games/Fallout 4"));
        assert_eq!(installation.data_path, None);
        assert_eq!(installation.f4se_plugins_path, None);
        assert!(!installation.has_data_path());
        assert!(!installation.has_f4se_plugins_path());
        assert_eq!(installation.install_type.as_reference_str(), "Unknown");
    }

    #[test]
    fn fallout4_installation_can_carry_optional_derived_paths() {
        let installation = Fallout4Installation::with_optional_paths(
            "C:/Games/Fallout 4",
            Some("C:/Games/Fallout 4/Data"),
            Some("C:/Games/Fallout 4/Data/F4SE/Plugins"),
        );

        assert_eq!(
            installation.data_path.as_deref(),
            Some(Path::new("C:/Games/Fallout 4/Data"))
        );
        assert_eq!(
            installation.f4se_plugins_path.as_deref(),
            Some(Path::new("C:/Games/Fallout 4/Data/F4SE/Plugins"))
        );
        assert!(installation.has_data_path());
        assert!(installation.has_f4se_plugins_path());
    }

    #[test]
    fn archive_module_and_ini_records_are_pure_domain_state() {
        let mut installation = Fallout4Installation::new("C:/Games/Fallout 4");
        installation.archives.push(ArchiveRecord::new(
            "C:/Games/Fallout 4/Data/Fallout4 - Textures.ba2",
            ArchiveFormat::DirectX10,
            ArchiveVersion::NextGen8,
            true,
        ));
        installation.modules.push(ModuleRecord::new(
            "C:/Games/Fallout 4/Data/Example.esl",
            ModuleKind::Light,
            ModuleHeaderVersion::Version100,
            true,
        ));
        installation
            .ini_files
            .fallout4
            .sections
            .entry("general".to_owned())
            .or_default()
            .insert("slanguage".to_owned(), "en".to_owned());

        assert_eq!(
            installation.archives[0].format.as_reference_magic(),
            Some("DX10")
        );
        assert_eq!(installation.archives[0].version.as_header_value(), 8);
        assert_eq!(
            installation.modules[0].header_version.as_reference_str(),
            Some("1.00")
        );
        assert_eq!(
            installation.ini_files.fallout4.get("general", "slanguage"),
            Some("en")
        );
    }

    #[test]
    fn install_type_and_semantic_version_reference_display_values_are_stable() {
        assert_eq!(Fallout4InstallType::OldGen.to_string(), "Old-Gen");
        assert_eq!(Fallout4InstallType::DownGrade.to_string(), "Down-Grade");
        assert_eq!(
            Fallout4InstallType::NextGenAnniversary.to_string(),
            "Next-Gen & Anniversary"
        );
        assert_eq!(Fallout4InstallType::NotFound.to_string(), "Not Found");
        assert_eq!(SemanticVersion::new(2, 5, 2).to_string(), "2.5.2");
        assert_eq!(SemanticVersion::zero().to_string(), "0.0.0");
    }

    #[test]
    fn discovery_not_found_error_is_recoverable_and_does_not_require_file_picker() {
        let error = DiscoveryError::fallout4_not_found(Some(
            "registry read failed: access denied to HKLM path".to_owned(),
        ));

        assert_eq!(error.kind, DiscoveryErrorKind::Fallout4NotFound);
        assert_eq!(
            error.user_message(),
            "A Fallout 4 installation could not be found."
        );
        assert!(error.is_recoverable());
        assert!(!error.requires_manual_file_picker());
        assert_eq!(
            error.diagnostic.as_deref(),
            Some("registry read failed: access denied to HKLM path")
        );
        assert!(!error.user_message().contains("HKLM"));
    }

    #[test]
    fn discovery_messages_keep_reference_path_exceptions() {
        let registry_error = DiscoveryError::invalid_registry_path("D:/Moved/Fallout 4");
        assert_eq!(
            registry_error.user_message(),
            "A Fallout 4 installation could not be found.\n\nThe path set in your registry is:\nD:/Moved/Fallout 4\n\nIf this is not correct, please run the Fallout 4 Launcher to correct it."
        );

        let known_folder_error =
            DiscoveryError::environment_folder_missing("C:/Users/Example/Documents");
        assert_eq!(
            known_folder_error.user_message(),
            "Folder does not exist:\nC:/Users/Example/Documents"
        );
    }

    #[test]
    fn tab_loading_error_messages_match_reference_text() {
        assert_eq!(
            DiscoveryError::data_folder_not_found().user_message(),
            "Data folder not found"
        );
        assert_eq!(
            DiscoveryError::f4se_plugins_folder_not_found(true).user_message(),
            "Data/F4SE/Plugins folder not found"
        );
        assert_eq!(
            DiscoveryError::f4se_plugins_folder_not_found(false).user_message(),
            "Data/F4SE/Plugins folder not found\nTry launching via your mod manager."
        );
    }
}

//! Fakeable filesystem adapter contracts for discovery and scan code.
//!
//! The real adapter performs ordinary filesystem reads and deterministic
//! directory traversal. Callers should depend on [`Filesystem`] so tests can use
//! in-memory fakes instead of a real Fallout 4 installation tree.

use std::{
    fs,
    io::Read,
    path::{Path, PathBuf},
};

use walkdir::WalkDir;

use crate::platform::{PlatformError, PlatformOperation, PlatformResult};

/// File type information exposed by filesystem adapters.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum FileType {
    /// Regular file.
    File,
    /// Directory.
    Directory,
    /// Symbolic link.
    Symlink,
    /// Any platform-specific file type not otherwise classified.
    Other,
}

impl FileType {
    fn from_std(file_type: fs::FileType) -> Self {
        if file_type.is_file() {
            Self::File
        } else if file_type.is_dir() {
            Self::Directory
        } else if file_type.is_symlink() {
            Self::Symlink
        } else {
            Self::Other
        }
    }
}

/// Metadata returned for a single filesystem path.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct FileMetadata {
    /// Classified file type.
    pub file_type: FileType,
    /// Byte length reported by the OS for files and other entries.
    pub len: u64,
}

impl FileMetadata {
    /// Returns true when this metadata describes a regular file.
    pub const fn is_file(&self) -> bool {
        matches!(self.file_type, FileType::File)
    }

    /// Returns true when this metadata describes a directory.
    pub const fn is_dir(&self) -> bool {
        matches!(self.file_type, FileType::Directory)
    }
}

/// Directory entry returned by direct and recursive enumeration.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct DirectoryEntry {
    /// Full path to the entry as supplied by the adapter.
    pub path: PathBuf,
    /// Classified file type for the entry.
    pub file_type: FileType,
}

impl DirectoryEntry {
    /// Creates a typed directory entry.
    pub fn new(path: impl Into<PathBuf>, file_type: FileType) -> Self {
        Self {
            path: path.into(),
            file_type,
        }
    }
}

/// Filesystem operations needed by discovery, scan, parser, and patch code.
pub trait Filesystem {
    /// Reads metadata for a path.
    fn metadata(&self, path: &Path) -> PlatformResult<FileMetadata>;

    /// Returns true when a path exists, false for not-found, and errors for unsafe ambiguity.
    fn exists(&self, path: &Path) -> PlatformResult<bool> {
        match self.metadata(path) {
            Ok(_) => Ok(true),
            Err(error) if error.kind == crate::platform::PlatformErrorKind::NotFound => Ok(false),
            Err(error) => Err(error),
        }
    }

    /// Returns true when a path is a regular file.
    fn is_file(&self, path: &Path) -> PlatformResult<bool> {
        match self.metadata(path) {
            Ok(metadata) => Ok(metadata.is_file()),
            Err(error) if error.kind == crate::platform::PlatformErrorKind::NotFound => Ok(false),
            Err(error) => Err(error),
        }
    }

    /// Returns true when a path is a directory.
    fn is_dir(&self, path: &Path) -> PlatformResult<bool> {
        match self.metadata(path) {
            Ok(metadata) => Ok(metadata.is_dir()),
            Err(error) if error.kind == crate::platform::PlatformErrorKind::NotFound => Ok(false),
            Err(error) => Err(error),
        }
    }

    /// Reads a whole file as bytes.
    fn read_bytes(&self, path: &Path) -> PlatformResult<Vec<u8>>;

    /// Reads at most `max_len` bytes from the start of a file.
    ///
    /// Real adapters should override this to avoid full-file reads for parser
    /// probes. The default keeps existing fakes small while preserving the same
    /// error behavior as [`Filesystem::read_bytes`].
    fn read_prefix(&self, path: &Path, max_len: usize) -> PlatformResult<Vec<u8>> {
        let mut bytes = self.read_bytes(path)?;
        bytes.truncate(max_len);
        Ok(bytes)
    }

    /// Reads a whole UTF-8 text file.
    fn read_to_string(&self, path: &Path) -> PlatformResult<String>;

    /// Lists direct children of a directory in deterministic path order.
    fn read_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>>;

    /// Recursively lists a directory tree in deterministic path order.
    fn walk_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>>;
}

/// Production filesystem adapter backed by `std::fs` and deterministic `walkdir` traversal.
#[derive(Debug, Default, Clone, Copy)]
pub struct RealFilesystem;

impl RealFilesystem {
    /// Creates the production filesystem adapter without touching the filesystem.
    pub const fn new() -> Self {
        Self
    }
}

impl Filesystem for RealFilesystem {
    fn metadata(&self, path: &Path) -> PlatformResult<FileMetadata> {
        fs::metadata(path)
            .map(|metadata| FileMetadata {
                file_type: FileType::from_std(metadata.file_type()),
                len: metadata.len(),
            })
            .map_err(|error| {
                PlatformError::from_io(
                    PlatformOperation::ReadMetadata,
                    path.display().to_string(),
                    &error,
                )
            })
    }

    fn read_bytes(&self, path: &Path) -> PlatformResult<Vec<u8>> {
        fs::read(path).map_err(|error| {
            PlatformError::from_io(
                PlatformOperation::ReadFile,
                path.display().to_string(),
                &error,
            )
        })
    }

    fn read_prefix(&self, path: &Path, max_len: usize) -> PlatformResult<Vec<u8>> {
        let mut file = fs::File::open(path).map_err(|error| {
            PlatformError::from_io(
                PlatformOperation::ReadFile,
                path.display().to_string(),
                &error,
            )
        })?;
        let mut bytes = Vec::with_capacity(max_len);
        file.by_ref()
            .take(max_len as u64)
            .read_to_end(&mut bytes)
            .map_err(|error| {
                PlatformError::from_io(
                    PlatformOperation::ReadFile,
                    path.display().to_string(),
                    &error,
                )
            })?;
        Ok(bytes)
    }

    fn read_to_string(&self, path: &Path) -> PlatformResult<String> {
        fs::read_to_string(path).map_err(|error| {
            PlatformError::from_io(
                PlatformOperation::ReadFile,
                path.display().to_string(),
                &error,
            )
        })
    }

    fn read_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>> {
        let mut entries = Vec::new();
        let iterator = fs::read_dir(path).map_err(|error| {
            PlatformError::from_io(
                PlatformOperation::ReadDirectory,
                path.display().to_string(),
                &error,
            )
        })?;

        for entry in iterator {
            let entry = entry.map_err(|error| {
                PlatformError::from_io(
                    PlatformOperation::ReadDirectory,
                    path.display().to_string(),
                    &error,
                )
            })?;
            let entry_path = entry.path();
            let file_type = entry.file_type().map_err(|error| {
                PlatformError::from_io(
                    PlatformOperation::ReadMetadata,
                    entry_path.display().to_string(),
                    &error,
                )
            })?;
            entries.push(DirectoryEntry::new(
                entry_path,
                FileType::from_std(file_type),
            ));
        }

        entries.sort_by(|left, right| left.path.cmp(&right.path));
        Ok(entries)
    }

    fn walk_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>> {
        let mut entries = Vec::new();
        for entry in WalkDir::new(path).sort_by_file_name() {
            let entry = entry.map_err(|error| walkdir_error(path, error))?;
            let file_type = entry.file_type();
            let file_type = if file_type.is_file() {
                FileType::File
            } else if file_type.is_dir() {
                FileType::Directory
            } else if file_type.is_symlink() {
                FileType::Symlink
            } else {
                FileType::Other
            };
            entries.push(DirectoryEntry::new(entry.path().to_path_buf(), file_type));
        }
        Ok(entries)
    }
}

fn walkdir_error(root: &Path, error: walkdir::Error) -> PlatformError {
    let target = error.path().unwrap_or(root).display().to_string();
    if let Some(io_error) = error.io_error() {
        PlatformError::from_io(PlatformOperation::WalkDirectory, target, io_error)
    } else {
        PlatformError::command_failed(PlatformOperation::WalkDirectory, target, error.to_string())
    }
}

#[cfg(test)]
mod tests {
    use std::collections::{BTreeMap, BTreeSet};

    use crate::platform::{PlatformErrorKind, PlatformOperation};

    use super::*;

    #[derive(Debug, Clone, PartialEq, Eq)]
    enum FakeNode {
        File(Vec<u8>),
        Directory,
        Denied,
    }

    #[derive(Debug, Default)]
    struct FakeFilesystem {
        nodes: BTreeMap<PathBuf, FakeNode>,
    }

    impl FakeFilesystem {
        fn with_file(mut self, path: &str, bytes: impl Into<Vec<u8>>) -> Self {
            self.nodes
                .insert(PathBuf::from(path), FakeNode::File(bytes.into()));
            self
        }

        fn with_dir(mut self, path: &str) -> Self {
            self.nodes.insert(PathBuf::from(path), FakeNode::Directory);
            self
        }

        fn with_denied(mut self, path: &str) -> Self {
            self.nodes.insert(PathBuf::from(path), FakeNode::Denied);
            self
        }

        fn node(&self, path: &Path, operation: PlatformOperation) -> PlatformResult<&FakeNode> {
            match self.nodes.get(path) {
                Some(FakeNode::Denied) => Err(PlatformError::new(
                    operation,
                    path.display().to_string(),
                    PlatformErrorKind::PermissionDenied,
                    format!(
                        "{} target could not be accessed because permission was denied.",
                        operation.label()
                    ),
                )),
                Some(node) => Ok(node),
                None => Err(PlatformError::new(
                    operation,
                    path.display().to_string(),
                    PlatformErrorKind::NotFound,
                    format!("{} target was not found.", operation.label()),
                )),
            }
        }
    }

    impl Filesystem for FakeFilesystem {
        fn metadata(&self, path: &Path) -> PlatformResult<FileMetadata> {
            let node = self.node(path, PlatformOperation::ReadMetadata)?;
            let file_type = match node {
                FakeNode::File(bytes) => {
                    return Ok(FileMetadata {
                        file_type: FileType::File,
                        len: bytes.len() as u64,
                    });
                }
                FakeNode::Directory => FileType::Directory,
                FakeNode::Denied => unreachable!("denied nodes return before classification"),
            };
            Ok(FileMetadata { file_type, len: 0 })
        }

        fn read_bytes(&self, path: &Path) -> PlatformResult<Vec<u8>> {
            match self.node(path, PlatformOperation::ReadFile)? {
                FakeNode::File(bytes) => Ok(bytes.clone()),
                FakeNode::Directory => Err(PlatformError::new(
                    PlatformOperation::ReadFile,
                    path.display().to_string(),
                    PlatformErrorKind::InvalidInput,
                    "File read target is invalid.",
                )),
                FakeNode::Denied => unreachable!("denied nodes return before reads"),
            }
        }

        fn read_to_string(&self, path: &Path) -> PlatformResult<String> {
            String::from_utf8(self.read_bytes(path)?).map_err(|error| {
                PlatformError::parse_error(
                    PlatformOperation::ReadFile,
                    path.display().to_string(),
                    error.to_string(),
                )
            })
        }

        fn read_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>> {
            self.node(path, PlatformOperation::ReadDirectory)?;
            let mut entries = Vec::new();
            for (candidate, node) in &self.nodes {
                if candidate.parent() == Some(path) {
                    let file_type = match node {
                        FakeNode::File(_) => FileType::File,
                        FakeNode::Directory => FileType::Directory,
                        FakeNode::Denied => FileType::Other,
                    };
                    entries.push(DirectoryEntry::new(candidate.clone(), file_type));
                }
            }
            Ok(entries)
        }

        fn walk_dir(&self, path: &Path) -> PlatformResult<Vec<DirectoryEntry>> {
            self.node(path, PlatformOperation::WalkDirectory)?;
            let mut entries = Vec::new();
            for (candidate, node) in &self.nodes {
                if candidate == path || candidate.starts_with(path) {
                    let file_type = match node {
                        FakeNode::File(_) => FileType::File,
                        FakeNode::Directory => FileType::Directory,
                        FakeNode::Denied => FileType::Other,
                    };
                    entries.push(DirectoryEntry::new(candidate.clone(), file_type));
                }
            }
            Ok(entries)
        }
    }

    fn collect_files(fs: &dyn Filesystem, root: &Path) -> PlatformResult<BTreeSet<PathBuf>> {
        Ok(fs
            .walk_dir(root)?
            .into_iter()
            .filter(|entry| entry.file_type == FileType::File)
            .map(|entry| entry.path)
            .collect())
    }

    #[test]
    fn fake_filesystem_drives_scan_style_directory_inputs() {
        let fs = FakeFilesystem::default()
            .with_dir("Data")
            .with_file("Data/Fallout4.esm", b"plugin".to_vec())
            .with_file("Data/Fallout4 - Main.ba2", b"archive".to_vec())
            .with_dir("Data/F4SE");

        let files = collect_files(&fs, Path::new("Data")).expect("fake traversal should work");

        assert_eq!(
            files,
            BTreeSet::from([
                PathBuf::from("Data/Fallout4 - Main.ba2"),
                PathBuf::from("Data/Fallout4.esm"),
            ])
        );
        assert!(fs.is_dir(Path::new("Data")).expect("fake dir metadata"));
        assert!(
            fs.is_file(Path::new("Data/Fallout4.esm"))
                .expect("fake file metadata")
        );
        assert_eq!(
            fs.read_to_string(Path::new("Data/Fallout4.esm"))
                .expect("fake text read"),
            "plugin"
        );
    }

    #[test]
    fn fake_filesystem_surfaces_typed_failure_without_real_paths() {
        let fs = FakeFilesystem::default()
            .with_dir("Data")
            .with_denied("Data/Private.ba2");

        let error = fs
            .metadata(Path::new("Data/Private.ba2"))
            .expect_err("denied fake path should fail");

        assert_eq!(error.operation, PlatformOperation::ReadMetadata);
        assert_eq!(error.kind, PlatformErrorKind::PermissionDenied);
        assert_eq!(
            error.user_message(),
            "Filesystem metadata read target could not be accessed because permission was denied."
        );
    }

    #[test]
    fn real_filesystem_missing_file_maps_to_typed_not_found() {
        let fs = RealFilesystem::new();
        let missing = Path::new("definitely-not-a-cmt-rs-platform-test-file.nope");

        let error = fs
            .read_bytes(missing)
            .expect_err("missing file should produce typed failure");

        assert_eq!(error.kind, PlatformErrorKind::NotFound);
        assert_eq!(error.operation, PlatformOperation::ReadFile);
        assert_eq!(error.user_message(), "File read target was not found.");
    }
}

