                    &app,
                    &overview_controller,
                    worker_runtime,
                    overview_sink.clone(),
                    OverviewDeferredActionKind::OpenUpdateProvider(UpdateProvider::NexusMods),
                    "Nexus Mods update link is not available.",
                    |controller| controller.update_provider_action(UpdateProvider::NexusMods),
