            .as_ref()
            .map(|error| error.summary.clone())
            .unwrap_or_default(),
        disabled_utility_status: state
            .disabled_utility_status
            .clone()
            .unwrap_or_else(|| TOOLS_DEFAULT_DISABLED_UTILITY_STATUS.to_owned()),
    }
