                diagnostic = %error,
                "Tools controller state is unavailable"
            );
            None
        }
    }
}

fn with_about_controller_mut<T>(
    controller: &Arc<Mutex<AboutController>>,
    action: impl FnOnce(&mut AboutController) -> T,
) -> Option<T> {
    match controller.lock() {
